-- ============================================================================
-- BPM Intelligence — COMPLETE SETUP (run once)
-- In Supabase: SQL Editor -> paste this whole file -> Run.
-- Includes schema + security + storage + the 陳氏家 seed data.
-- ============================================================================

-- ============================================================================
-- BPM Intelligence — 0001 init schema
-- Multi-tenant report platform. Run in Supabase SQL editor (or `supabase db push`).
-- ============================================================================
create extension if not exists pgcrypto;

-- Tenants ---------------------------------------------------------------------
create table if not exists public.clients (
  id         uuid primary key default gen_random_uuid(),
  name       text not null,
  slug       text unique,
  config     jsonb,
  created_at timestamptz not null default now()
);

-- One row per auth user (role lives here) -------------------------------------
create table if not exists public.profiles (
  id         uuid primary key references auth.users(id) on delete cascade,
  email      text,
  full_name  text,
  role       text not null default 'user' check (role in ('admin','user')),
  created_at timestamptz not null default now()
);

-- Which users can see which clients (admins see all, regardless) ---------------
create table if not exists public.memberships (
  user_id    uuid not null references public.profiles(id) on delete cascade,
  client_id  uuid not null references public.clients(id) on delete cascade,
  created_at timestamptz not null default now(),
  primary key (user_id, client_id)
);

-- Assets ----------------------------------------------------------------------
create table if not exists public.assets (
  id            uuid primary key default gen_random_uuid(),
  client_id     uuid not null references public.clients(id) on delete cascade,
  code          text not null,                 -- e.g. 'asset-001' (used in URLs)
  name          text not null,
  type          text,
  location      text,
  ownership_meta text,
  status        text,
  status_color  text,
  sort_order    int default 0,
  created_at    timestamptz not null default now(),
  unique (client_id, code)
);

-- Reporting periods (monthly), draft until published --------------------------
create table if not exists public.periods (
  id           uuid primary key default gen_random_uuid(),
  client_id    uuid not null references public.clients(id) on delete cascade,
  period       text not null,                  -- e.g. '2026-05'
  label        text,                           -- e.g. '2026年5月'
  published    boolean not null default false,
  published_at timestamptz,
  created_at   timestamptz not null default now(),
  unique (client_id, period)
);

-- Portfolio-level report blob (mirrors portfolio.json) ------------------------
create table if not exists public.portfolio_data (
  client_id  uuid not null references public.clients(id) on delete cascade,
  period_id  uuid not null references public.periods(id) on delete cascade,
  data       jsonb not null default '{}'::jsonb,
  updated_at timestamptz not null default now(),
  primary key (client_id, period_id)
);

-- Per-asset, per-section report blob (mirrors the section JSON files) ----------
create table if not exists public.asset_section_data (
  asset_id   uuid not null references public.assets(id) on delete cascade,
  period_id  uuid not null references public.periods(id) on delete cascade,
  section    text not null check (section in
              ('overview','ownership-capital','financial','risk','operations','documents','market')),
  data       jsonb not null default '{}'::jsonb,
  updated_at timestamptz not null default now(),
  primary key (asset_id, period_id, section)
);

-- Uploaded documents (files live in Storage; this is the index) ---------------
create table if not exists public.documents (
  id          uuid primary key default gen_random_uuid(),
  client_id   uuid not null references public.clients(id) on delete cascade,
  asset_id    uuid references public.assets(id) on delete set null,
  period_id   uuid references public.periods(id) on delete set null,
  title       text not null,
  category    text,
  doc_type    text,
  storage_path text not null,                  -- documents/<client_id>/<file>
  size_bytes  bigint,
  uploaded_by uuid references public.profiles(id),
  created_at  timestamptz not null default now()
);

-- User -> admin requests ------------------------------------------------------
create table if not exists public.requests (
  id              uuid primary key default gen_random_uuid(),
  client_id       uuid not null references public.clients(id) on delete cascade,
  created_by      uuid not null references public.profiles(id) on delete cascade,
  subject         text not null,
  message         text,
  attachment_path text,
  status          text not null default 'open' check (status in ('open','closed')),
  created_at      timestamptz not null default now(),
  resolved_at     timestamptz,
  resolved_by     uuid references public.profiles(id)
);

-- Indexes ---------------------------------------------------------------------
create index if not exists idx_memberships_client on public.memberships (client_id);
create index if not exists idx_assets_client      on public.assets (client_id);
create index if not exists idx_periods_client_pub on public.periods (client_id, published);
create index if not exists idx_asd_period         on public.asset_section_data (period_id);
create index if not exists idx_documents_client   on public.documents (client_id);
create index if not exists idx_requests_client_st on public.requests (client_id, status);

-- Auto-create a profile row whenever an auth user is created ------------------
create or replace function public.handle_new_user()
returns trigger
language plpgsql
security definer
set search_path = public
as $$
begin
  insert into public.profiles (id, email, full_name)
  values (new.id, new.email, coalesce(new.raw_user_meta_data->>'full_name', ''))
  on conflict (id) do nothing;
  return new;
end;
$$;

drop trigger if exists on_auth_user_created on auth.users;
create trigger on_auth_user_created
  after insert on auth.users
  for each row execute function public.handle_new_user();

-- ===================== SECURITY (RLS) =====================

-- ============================================================================
-- BPM Intelligence — 0002 Row-Level Security
-- Run AFTER 0001. Defines who can read/write each table.
--   admin : full access to everything
--   user  : read only their client's PUBLISHED data; create their own requests
-- ============================================================================

-- Helper functions (security definer => can read profiles/memberships safely) --
create or replace function public.is_admin()
returns boolean language sql stable security definer set search_path = public as $$
  select exists (select 1 from public.profiles where id = auth.uid() and role = 'admin');
$$;

create or replace function public.has_client_access(cid uuid)
returns boolean language sql stable security definer set search_path = public as $$
  select public.is_admin()
      or exists (select 1 from public.memberships m
                 where m.user_id = auth.uid() and m.client_id = cid);
$$;

-- Enable RLS ------------------------------------------------------------------
alter table public.clients            enable row level security;
alter table public.profiles           enable row level security;
alter table public.memberships        enable row level security;
alter table public.assets             enable row level security;
alter table public.periods            enable row level security;
alter table public.portfolio_data     enable row level security;
alter table public.asset_section_data enable row level security;
alter table public.documents          enable row level security;
alter table public.requests           enable row level security;

-- clients ---------------------------------------------------------------------
drop policy if exists clients_select on public.clients;
create policy clients_select on public.clients
  for select using (public.has_client_access(id));
drop policy if exists clients_admin on public.clients;
create policy clients_admin on public.clients
  for all using (public.is_admin()) with check (public.is_admin());

-- profiles --------------------------------------------------------------------
drop policy if exists profiles_select on public.profiles;
create policy profiles_select on public.profiles
  for select using (id = auth.uid() or public.is_admin());
drop policy if exists profiles_admin on public.profiles;
create policy profiles_admin on public.profiles
  for all using (public.is_admin()) with check (public.is_admin());

-- memberships -----------------------------------------------------------------
drop policy if exists memberships_select on public.memberships;
create policy memberships_select on public.memberships
  for select using (user_id = auth.uid() or public.is_admin());
drop policy if exists memberships_admin on public.memberships;
create policy memberships_admin on public.memberships
  for all using (public.is_admin()) with check (public.is_admin());

-- assets ----------------------------------------------------------------------
drop policy if exists assets_select on public.assets;
create policy assets_select on public.assets
  for select using (public.has_client_access(client_id));
drop policy if exists assets_admin on public.assets;
create policy assets_admin on public.assets
  for all using (public.is_admin()) with check (public.is_admin());

-- periods (users see only published) ------------------------------------------
drop policy if exists periods_select on public.periods;
create policy periods_select on public.periods
  for select using (public.has_client_access(client_id) and (published or public.is_admin()));
drop policy if exists periods_admin on public.periods;
create policy periods_admin on public.periods
  for all using (public.is_admin()) with check (public.is_admin());

-- portfolio_data (client access + period published, unless admin) -------------
drop policy if exists portfolio_data_select on public.portfolio_data;
create policy portfolio_data_select on public.portfolio_data
  for select using (
    public.has_client_access(client_id)
    and (public.is_admin() or exists (
      select 1 from public.periods p where p.id = period_id and p.published
    ))
  );
drop policy if exists portfolio_data_admin on public.portfolio_data;
create policy portfolio_data_admin on public.portfolio_data
  for all using (public.is_admin()) with check (public.is_admin());

-- asset_section_data ----------------------------------------------------------
drop policy if exists asd_select on public.asset_section_data;
create policy asd_select on public.asset_section_data
  for select using (
    exists (select 1 from public.assets a
            where a.id = asset_id and public.has_client_access(a.client_id))
    and (public.is_admin() or exists (
      select 1 from public.periods p where p.id = period_id and p.published
    ))
  );
drop policy if exists asd_admin on public.asset_section_data;
create policy asd_admin on public.asset_section_data
  for all using (public.is_admin()) with check (public.is_admin());

-- documents -------------------------------------------------------------------
drop policy if exists documents_select on public.documents;
create policy documents_select on public.documents
  for select using (public.has_client_access(client_id));
drop policy if exists documents_admin on public.documents;
create policy documents_admin on public.documents
  for all using (public.is_admin()) with check (public.is_admin());

-- requests (users create + read their own; admins read/resolve all) -----------
drop policy if exists requests_insert on public.requests;
create policy requests_insert on public.requests
  for insert with check (created_by = auth.uid() and public.has_client_access(client_id));
drop policy if exists requests_select on public.requests;
create policy requests_select on public.requests
  for select using (created_by = auth.uid() or public.is_admin());
drop policy if exists requests_update on public.requests;
create policy requests_update on public.requests
  for update using (public.is_admin()) with check (public.is_admin());
drop policy if exists requests_delete on public.requests;
create policy requests_delete on public.requests
  for delete using (public.is_admin());

-- ===================== STORAGE =====================

-- ============================================================================
-- BPM Intelligence — 0003 Storage buckets + policies
-- Run AFTER 0002. Two PRIVATE buckets.
--   documents            : path 'documents/<client_id>/<file>'        admin writes, members read
--   request-attachments  : path '<client_id>/<user_id>/<file>'        members write, owner/admin read
-- ============================================================================

insert into storage.buckets (id, name, public)
values ('documents', 'documents', false)
on conflict (id) do nothing;

insert into storage.buckets (id, name, public)
values ('request-attachments', 'request-attachments', false)
on conflict (id) do nothing;

-- documents bucket ------------------------------------------------------------
drop policy if exists "documents read" on storage.objects;
create policy "documents read" on storage.objects
  for select using (
    bucket_id = 'documents' and (
      public.is_admin()
      or (split_part(name, '/', 1))::uuid in
         (select client_id from public.memberships where user_id = auth.uid())
    )
  );

drop policy if exists "documents admin insert" on storage.objects;
create policy "documents admin insert" on storage.objects
  for insert with check (bucket_id = 'documents' and public.is_admin());

drop policy if exists "documents admin update" on storage.objects;
create policy "documents admin update" on storage.objects
  for update using (bucket_id = 'documents' and public.is_admin());

drop policy if exists "documents admin delete" on storage.objects;
create policy "documents admin delete" on storage.objects
  for delete using (bucket_id = 'documents' and public.is_admin());

-- request-attachments bucket --------------------------------------------------
drop policy if exists "req-att insert" on storage.objects;
create policy "req-att insert" on storage.objects
  for insert with check (
    bucket_id = 'request-attachments' and
    (split_part(name, '/', 1))::uuid in
      (select client_id from public.memberships where user_id = auth.uid())
  );

drop policy if exists "req-att read" on storage.objects;
create policy "req-att read" on storage.objects
  for select using (
    bucket_id = 'request-attachments' and (
      public.is_admin()
      or (split_part(name, '/', 2))::uuid = auth.uid()
    )
  );

drop policy if exists "req-att admin delete" on storage.objects;
create policy "req-att admin delete" on storage.objects
  for delete using (bucket_id = 'request-attachments' and public.is_admin());

