  select a.id, pe.id, $c$overview$c$, $j${"summary":{"narrative":"淡水河岸資產為新北市淡水區中正路128號一棟12戶住宅/商業混合用途建築，於2019年3月取得。受益於淡水區觀光商圈持續成長及有效的資本改善計畫，資產自取得以來已增值約41.6%。目前有兩間住宅空置，正進行翻修以提升裝潢品質並達到市場租金水準。穩定戶型的入住率達92%，償債覆蓋率健全為2.00倍，淨業主權益約為新台幣6,242萬元。近期主要決策為：是否於目前利率環境下向台北富邦銀行辦理再融資，以支應剩餘資本支出計畫，或延至2026年第四季待短期利率可能下降後再行辦理。","period":"2026年2月","preparedBy":"Asset Intelligence 資產智能平台","keyMessage":"資產穩定持續增值。第二期（4B及7A戶）翻修工程已完成發包，預計2026年3月開工。需於2026年6月30日前完成與台北富邦銀行之再融資決策。"},"basicInfo":{"assetName":"淡水河岸住商資產","assetType":"住宅/商業混合用途","location":"新北市淡水區中正路128號","submarket":"淡水/漁人碼頭，新北市","yearBuilt":1975,"yearAcquired":2019,"totalUnits":12,"residentialUnits":10,"commercialUnits":2,"totalGSF":11400,"siteAreaSF":6200,"parking":"4個平面停車位","currentStatus":"持有並改善","reportingPeriod":"2026年2月","ownershipSummary":"由淡水河岸置業有限公司持有（台灣公司）。主要所有人：陳氏家族信託（80%）。共同投資人：宏達資本有限合夥事業（20%）。"},"keyFigures":[{"label":"每m²均價","value":"$112,868","subLabel":"每m²市場估值","trend":"up","trendValue":"+$4,100 vs 去年"},{"label":"入住率（穩定戶）","value":"92%","subLabel":"10戶穩定戶中10戶","trend":"flat","trendValue":"穩定"},{"label":"貸款餘額","value":"$58.3M","subLabel":"截至2026年5月","trend":"down","trendValue":"-$88K 年初至今"},{"label":"業主淨權益","value":"$61.3M","subLabel":"資產價值扣除貸款","trend":"up","trendValue":"+$3.0M 年增"}],"kpiCards":[{"id":"noi","title":"淨營業收益 (NOI)","value":"$7.0M","period":"過去12個月","trend":"+3.1% 優於去年同期","trendDir":"up","chartType":"bar","chartData":{"labels":["Q1'25","Q2'25","Q3'25","Q4'25","Q1'26E"],"values":[1612205,1638000,1734000,1782000,1840000]}},{"id":"debt_coverage","title":"償債覆蓋率 (DSCR)","value":"2.00x","period":"過去12個月 DSCR","trend":"優於1.25x財務契約要求","trendDir":"up","chartType":"line","chartData":{"labels":["Feb'25","Apr'25","Jun'25","Aug'25","Oct'25","Dec'25","Feb'26"],"values":[1.94,1.94,1.97,1.98,1.97,2.01,2.02]}},{"id":"net_cashflow","title":"淨現金流量","value":"$3.5M","period":"過去12個月","trend":"+6.4% 優於去年同期","trendDir":"up","chartType":"bar","chartData":{"labels":["Q1'25","Q2'25","Q3'25","Q4'25","Q1'26E"],"values":[719488,731000,