"廠商","date":"2021-10-01","source":"信義物業管理","relatedSection":"營運","type":"PDF","url":"#","notes":"EGI 5%；2026年9月到期"},{"id":"DOC-022","name":"保險單 — 財產及責任","category":"廠商","date":"2025-07-15","source":"富邦產險","relatedSection":"風險","type":"PDF","url":"#","notes":"2026年7月到期須續約"},{"id":"DOC-023","name":"台北大安區市場報告 Q1 2026","category":"市場","date":"2026-04-10","source":"信義房屋研究中心","relatedSection":"市場","type":"PDF","url":"#","notes":"次市場空置率、租金走勢"},{"id":"DOC-024","name":"竣工平面圖","category":"圖說","date":"2019-05-01","source":"建築師事務所","relatedSection":"總覽","type":"DWG","url":"#","notes":"12戶配置；1975年建物"},{"id":"DOC-025","name":"建物現況照片 — 2026年5月","category":"圖說","date":"2026-05-01","source":"物業管理人","relatedSection":"總覽","type":"ZIP","url":"#","notes":"現況照片 — 外觀及各戶型"},{"id":"DOC-026","name":"2026年5月資產報告","category":"報告","date":"2026-05-08","source":"Asset Intelligence","relatedSection":"總覽","type":"PDF","url":"#","notes":"當期報告（本文件）"}]}$j$::jsonb
