insert into public.asset_section_data (asset_id, period_id, section, data)
  select a.id, pe.id, $c$market$c$, $j${"summary":{"submarket":"淡水/漁人碼頭，新北市","reportDate":"2026年5月","narrative":"新北市淡水次市場受惠於觀光商圈持續人流及捷運淡水線帶動的通勤租屋需求，2026年第一季住宅空置率維持在5.8%，與前季持平。要求租金年增2.5%，商業空間受漁人碼頭周邊人潮支撐，維持穩定。可比較住商混合用途資產的資本化率介於4.2%至5.8%，反映淡水相對台北市區較高的收益率。淡水河岸資產地處中正路主幹道商圈，翻修後戶型租金競爭力強，一樓商業空間具備穩定客群支撐。","outlook":"偏正面","keyThemes":["捷運通勤族支撐住宅租屋需求；淡水線每日旅運量逾12萬人次","漁人碼頭及老街觀光商圈維持商業空間穩定需求","租金成長溫和但穩健，年增2.5%","新供給受限；淡水中正路核心地段新建住商大樓稀少","租賃住宅管理條例修訂（立法院2026年第三季審議）為主要法規風險"]},"assetCompetitiveness":{"overall":"具競爭力","strengths":["地處淡水中正路核心商圈，步行可達捷運淡水站","近期翻修戶型（第一期已完工；第二期進行中）","商業用途收入提供非住宅多元化，受觀光人潮支撐","低LTV（48.7%）有利再融資定價"],"weaknesses":["4戶低於市場租金3%以上 — 等待下次續租時有上調空間","1975年建物；屋頂及機電設備老化","4個平面車位對比新建產品競爭定位不足"],"opportunities":["2戶翻修後租金提升NT$9,400/戶/月","一樓商業租金低於市場約6%；2027年到期時可調整","安裝EV充電設施可吸引優質租戶並支撐溢價"],"threats":["租賃住宅管理條例修訂草案審議中","全市公告地價及房屋稅調漲成本持續上升","淡水新市鎮區域2027年有新建競品預計交屋"]},"comparables":[{"address":"新北市淡水區中正路88號","type":"住宅/商業混合用途","units":14,"yearBuilt":1977,"soldDate":"2025-10-15","salePrice":138642000,"pricePerUnit":9903000,"pricePM2":122000,"capRate":"4.9%","occupancy":"91%","notes":"相近年份；規模略大"},{"address":"新北市淡水區英專路42號","type":"住宅","units":10,"yearBuilt":1973,"soldDate":"2025-08-22","salePrice":106284000,"pricePerUnit":10628400,"pricePM2":115700,"capRate":"5.1%","occupancy":"89%","notes":"無商業空間；NOI較低"},{"address":"新北市淡水區中正路156號","type":"住宅/商業混合用途","units":12,"yearBuilt":1972,"soldDate":"2026-02-10","salePrice":120834000,"pricePerUnit":10069500,"pricePM2":114100,"capRate":"5.3%","occupancy":"93%","notes":"最具可比性；年份及格局相近"},{"address":"新北市淡水區民族路18號","type":"住宅","units":8,"yearBuilt":1976,"soldDate":"2025-12-05","salePrice":83427000,"pricePerUnit":10428375,"pricePM2":110600,"notes":"規模較小；入住率較低；裝潢水準較低","capRate":"5.6%","occupancy":"87%"}],"rentComparables":[{"address":"中正路88號","unitType":"1房","areaM2":63,"askingRent":41400,"rentPM2":657,"occupancy":"93%","amenities":"翻修"},{"address":"英專路42號","unitType":"1房","areaM2":60,"askingRent":38700,"rentPM2":645,"occupancy":"90%","amenities":"標準"},{"address":"中正路156號","unitType":"1房","areaM2":65,"askingRent":40500,"rentPM2":623,"occupancy":"92%","amenities":"翻新"},{"address":"淡水河岸（本案）","unitType":"1房 穩定戶","areaM2":67,"askingRent":39400,"rentPM2":588,"occupancy":"94%","amenities":"翻修"},{"address":"中正路88號","unitType":"2房","areaM2":87,"askingRent":58200,"rentPM2":669,"occupancy":"91%","amenities":"翻修"},{"address":"中正路156號","unitType":"2房","areaM2":89,"askingRent":55800,"rentPM2":627,"occupancy":"90%","amenities":"翻新"},{"address":"淡水河岸（本案）","unitType":"2房 穩定戶","areaM2":91,"askingRent":54100,"rentPM2":595,"occupancy":"89%","amenities":"翻修"}],"capRateTrend":{"labels":["Q1'23","Q2'23","Q3'23","Q4'23","Q1'24","Q2'24","Q3'24","Q4'24","Q1'25","Q2'25","Q3'25","Q4'25","Q1'26"],"values":[5.8,5.75,5.7,5.65,5.55,5.48,5.42,5.38,5.32,5.28,5.22,5.18,5.15]},"vacancyTrend":{"labels":["Q1'23","Q2'23","Q3'23","Q4'23","Q1'24","Q2'24","Q3'24","Q4'24","Q1'25","Q2'25","Q3'25","Q4'25","Q1'26"],"submarket":[6.2,6,5.8,5.6,5.4,5.2,5.4,5.6,5.7,5.8,5.9,5.8,5.8],"asset":[8.3,8.3,8.3,8.3,8.3,8.3,6.7,6.7,6.7,8.3,8.3,8.3,16.7]},"marketRisks":[{"title":"租賃住宅管理條例修訂","level":"High","description":"立法院預計2026年第三季審議。若通過，每年租金調漲上限為3%，低於目前市場成長率，將抑制NOI增長。"},{"title":"淡水觀光景氣波動","level":"Medium","description":"一樓商業租金依賴淡水觀光客流量。若主要景點翻修或交通調整造成旅客下降，商業租金可能承壓。"},{"title":"建築材料及工資通膨","level":"Medium","description":"勞工成本及建材費用持續上漲，提高資本支出需求並降低翻修投資報酬。"},{"title":"保險市場趨緊","level":"Low","description":"台灣商業不動產保險費率持續每年上漲6–10%，影響全市場。"}],"marketOpportunities":[{"title":"4戶低於市場租金之調整空間","description":"四戶租金低於市場行情3–6%。下次續租時調整租金，每年可增加NT$29萬至NT$46萬NOI。"},{"title":"2027年商業空間租金調升","description":"一樓商業租約2027年1月到期。目前租金低於市場約6%。以市場租金續約每年可增加約NT$134,000。"},{"title":"供給受限支撐資產價值","description":"中正路核心地段新建案稀少，同類型產品競爭有限，支撐估值及租金水準。"},{"title":"EV充電設施溢價潛力","description":"租戶對EV充電設施需求持續增加。安裝2組Level 2充電樁可支撐每個車位每月NT$4,500以上的溢價。"}],"marketImplication":{"title":"市場動態對淡水河岸資產的意涵","body":"淡水次市場基本面支持目前持有並改善的策略。捷運支撐的穩定通勤需求及觀光商圈帶動的商業人流，為資產價值提供有力支撐。主要風險——租賃管理條例修法——應密切追蹤，並在2026年第四季再融資財務模型中以悲觀情境反映。最具行動力的上行空間，在於下次續租時將4戶低市場租金進行正常化，此舉無需資本投入，即可每年增加NT$29萬至NT$46萬NOI。第二期翻修完工後，本資產競爭定位將顯著提升。"}}$j$::jsonb
  from public.assets a join public.periods pe on pe.client_id = a.client_id and pe.period = '2026-Q2'
  where a.code = $c$asset-001$c$ and a.client_id = (select id from public.clients where slug = 'chen-family')
  on conflict (asset_id, period_id, section) do update set data = excluded.data, updated_at = now();
insert into public.asset_section_data (asset_id, period_id, section, data)
  select a.id, pe.id, $c$overview$c$, $j${"summary":{"narrative":"林口全聯商業物業位於新北市林口區南勢民有街148號，為一宗商業零售用地及地上建物，土地面積約1,607m²，建物總樓地板面積約1,282m²，於2003年7月以NT$2,200萬元購入。本資產自2008年起長期出租予全聯福利中心股份有限公司，現行租約效期為2023年至2033年（10年），年租金收入NT$5,040,000，提供高度可預期之穩定現金流。受益於林口新市鎮快速開發及桃園機場捷運A7站通車效應，資產自取得以來增值逾961%，估計現值約NT$2億3,360萬元。現有土地銀行貸款餘額NT$2,784萬元，貸款成數僅11.9%，資產結構穩健。主要關注事項為2033年租約到期之租賃策略規劃，及2036年貸款到期之再融資安排。","period":"2026年5月","preparedBy":"Asset Intelligence 資產智能平台","keyMessage":"全聯租約穩定履行中，下次租金調漲排定於2027年1月。2033年租約到期前7年，宜啟動長期租賃策略規劃。貸款成數11.9%，資產結構高度穩健。"},"basicInfo":{"assetName":"林口全聯商業物業","assetType":"商業零售用地","location":"新北市林口區南勢民有街148號","submarket":"林口區，新北市","yearBuilt":2006,"yearAcquired":2003,"totalUnits":1,"residentialUnits":0,"commercialUnits":1,"totalGSF":13800,"siteAreaSF":17300,"parking":"25個平面停車位（含無障礙）","currentStatus":"穩定持有","reportingPeriod":"2026年5月","ownershipSummary":"由林口商業置產有限公司持有（台灣公司）。100%所有人：陳氏家族信託。"},"keyFigures":[{"label":"每m²均價","value":"$182,000","subLabel":"土地及建物綜合均價","trend":"up","trendValue":"+$12,000 vs 去年"},{"label":"租賃入住率","value":"100%","subLabel":"全聯福利中心（單一租戶）","trend":"flat","trendValue":"穩定"},{"label":"貸款餘額","value":"$27.8M","subLabel":"截至2026年5月","trend":"down","trendValue":"-$2.2M 年初至今"},{"label":"業主淨權益","value":"$205.7M","subLabel":"資產價值扣除貸款","trend":"up","trendValue":"+$13.5M 年增"}],"kpiCards":[{"id":"noi","title":"淨營業收益 (NOI)","value":"$4.3M","period":"過去12個月","trend":"+2.2% 優於去年同期","trendDir":"up","chartType":"bar","chartData":{"labels":["Q2'25","Q3'25","Q4'25","Q1'26","Q2'26E"],"values":[1056000,1092600,1056000,1110000,1116000]}},{"id":"debt_coverage","title":"償債覆蓋率 (DSCR)","value":"1.41x","period":"過去12個月 DSCR","trend":"優於1.25x財務契約要求","trendDir":"up","chartType":"line","chartData":{"labels":["May'25","Jul'25","Sep'25","Nov'25","Jan'26","Mar'26","May'26"],"values":[1.38,1.39,1.4,1.39,1.42,1.41,1.41]}},{"id":"net_cashflow","title":"淨現金流量","value":"$1.3M","period":"過去12個月","trend":"+4.0% 優於去年同期","trendDir":"up","chartType":"bar","chartData":{"labels":["Q2'25","Q3'25","Q4'25","Q1'26","Q2'26E"],"values":[288000,306000,291000,330000,312000]}},{"id":"ltv","title":"貸款成數 (LTV)","value":"11.9%","period":"目前貸款成數","trend":"較取得時偏低；結構穩健","trendDir":"up","chartType":"line","chartData":{"labels":["2020","2021","2022","2023","2024","2025","2026"],"values":[22.5,21.3,20.1,18.8,17.5,16.3,11.9]}}],"actions":[{"id":"act-001","title":"2033年租約到期 — 早期策略規劃","recommendation":"現行全聯租約將於2033年12月到期，距今約7年。建議於2026年下半年啟動租賃策略檢討，評估：（1）以市場行情與全聯辦理長期續約；（2）結束租賃後自行招租高租金業態；（3）評估改建重開發可行性。全聯目前租金低於林口區同類商業用地市場行情約6%，下次談判有調漲空間。","decisionNeeded":"確認2033年租賃策略方向；授權委任商業不動產顧問提供租賃市場意見","owner":"陳氏家族信託","priority":"Medium","deadline":"2026-12-31","status":"Open"},{"id":"act-002","title":"2027年1月租金調漲 — 確認執行","recommendation":"依據現行租約，全聯租金每2年調漲2.5%，下次調漲日期為2027年1月1日。調漲後月租金將自NT$420,000提升至NT$430,500，全年增加NT$126,000。建議提前確認通知義務及調漲計算方式，確保按時執行。","decisionNeeded":"確認已向全聯發出正式調漲通知（應於2026年10月前發出）","owner":"林口商業置產有限公司 / 物業管理人","priority":"High","deadline":"2026-10-01","status":"Open"},{"id":"act-003","title":"停車場翻新 — 改善設施競爭力","recommendation":"現有25個平面停車位，部分劃線及照明設備老化。建議投入約NT$480,000進行翻新，並安裝2組EV充電樁（約NT$260,000），可提升全聯顧客體驗，亦符合新北市商業用地設施更新補助資格。","decisionNeeded":"核准停車場翻新預算及EV充電設施安裝計畫","owner":"物業管理人","priority":"Low","deadline":"2026-09-30","status":"Open"}],"linkedDocuments":[{"name":"2026年5月資產報告（本文件）","category":"報告","date":"2026-05-08","type":"PDF"},{"name":"全聯租賃合約 — 2023年至2033年","category":"租賃","date":"2023-01-01","type":"PDF"},{"name":"2025年土地及建物鑑價報告","category":"估值","date":"2025-10-15","type":"PDF"},{"name":"土地銀行貸款合約","category":"融資","date":"2006-08-01","type":"PDF"}],"topRisks":[{"id":"R-01","title":"單一租戶集中風險（全聯）","level":"Medium","impact":"若全聯提前退租或無法續約，資產短期將面臨100%空置，NOI歸零，衝擊債務覆蓋比率"},{"id":"R-02","title":"實體零售電商替代壓力","level":"Medium","impact":"電子商務持續侵蝕實體超市流量；惟全聯獨特低價定位及生鮮採購習慣提供一定緩衝"},{"id":"R-03","title":"公告地價調漲導致稅負增加","level":"Low","impact":"新北市公告地價每2年調整；若上漲10%，地價稅年增約NT$24,000，影響有限"}],"marketSnapshot":{"submarket":"林口區，新北市","medianRentPM2":"$328/m²/月","vacancyRate":"4.8%","yoyRentGrowth":"+2.3%","assetVsMarket":"本資產現行租金低於林口區同類商業零售市場行情約6%，2033年租約到期時有顯著調漲空間。","capRateBenchmark":"可比資產2.8%–3.5%"}}$j$::jsonb
  from public.assets a join public.periods pe on pe.client_id = a.client_id and pe.period = '2026-Q2'
  where a.code = $c$asset-002$c$ and a.client_id = (select id from public.clients where slug = 'chen-family')
