  select a.id, pe.id, $c$overview$c$, $j${"summary":{"narrative":"大安仁愛苑為台北市大安區仁愛路四段285號一棟精品住宅大樓之高層戶，室內面積238m²（含公設共330m²），於2013年3月以預售方式購入，並於2016年5月交屋。本資產為陳氏家族信託自用持有，作為家族主要住所，目前無任何貸款，業主淨權益達NT$9,351萬元。自預售取得至今，資產增值約49.6%，以2026年5月估計市值計算。若按大安區同類豪宅市場行情評估，本資產具備月租金NT$15萬至NT$18萬之潛在出租價值，惟依家族使用規劃暫不考慮出租。目前無任何融資，以60%貸款成數計算，可動用之抵押融資空間約NT$5,611萬元，具備高度財務彈性。主要近期決策事項為委任正式鑑價（距上次鑑價已逾1年），以及評估室內裝潢翻新時程。","period":"2026年5月","preparedBy":"Asset Intelligence 資產智能平台","keyMessage":"自用豪宅，無貸款，淨權益NT$9,351萬。自預售至今增值49.6%。建議2026年下半年委任新一次正式鑑價，並評估室內翻新計畫（距完工已逾10年）。"},"basicInfo":{"assetName":"大安仁愛苑","assetType":"高級住宅（自用）","location":"台北市大安區仁愛路四段285號","submarket":"大安/仁愛路，台北市","yearBuilt":2016,"yearAcquired":2013,"totalUnits":1,"residentialUnits":1,"commercialUnits":0,"totalGSF":3552,"siteAreaSF":3552,"parking":"2個地下停車位（產權持分）","currentStatus":"自用持有","reportingPeriod":"2026年5月","ownershipSummary":"陳氏家族信託直接持有（個人名義）。無共同持有人。"},"keyFigures":[{"label":"每m²均價","value":"$283,000","subLabel":"豪宅市場估值基準","trend":"up","trendValue":"+$15,000 vs 去年"},{"label":"目前貸款","value":"NT$0","subLabel":"無任何抵押貸款","trend":"flat","trendValue":"零負債"},{"label":"業主淨權益","value":"$93.5M","subLabel":"100% 無貸款淨權益","trend":"up","trendValue":"+$4.8M 年增"},{"label":"可抵押空間","value":"$56.1M","subLabel":"60% LTV 可動用額度","trend":"up","trendValue":"財務彈性充裕"}],"kpiCards":[{"id":"market_value","title":"市場估值","value":"$93.5M","period":"2026年5月估計市值","trend":"+49.6% 自預售取得以來","trendDir":"up","chartType":"line","chartData":{"labels":["2013","2016","2018","2020","2022","2024","2026"],"values":[62400000,68376000,72624000,77792000,82376000,85624000,93512000]}},{"id":"net_equity","title":"業主淨權益","value":"$93.5M","period":"無貸款淨權益","trend":"100% 持有","trendDir":"up","chartType":"line","chartData":{"labels":["2013","2016","2018","2020","2022","2024","2026"],"values":[62400000,68376000,72624000,77792000,82376000,85624000,93512000]}},{"id":"ltv","title":"貸款成數 (LTV)","value":"0.0%","period":"目前貸款成數","trend":"無貸款；60% LTV 可動用NT$5,611萬","trendDir":"up","chartType":"line"