資","title":"再融資前利率急升","description":"若中央銀行在2026年7月到期前意外升息，再融資成本將進一步上升。情境：升息1碼（0.25%）每年約增加NT$21萬債務服務。","probability":2,"impact":4,"riskScore":8,"level":"High","owner":"蔡氏家族","mitigation":"向顧問詢問利率上限產品報價；評估2年期固定利率上限商品。2026年6月前啟動流程。","status":"Monitoring","reviewDate":"2026-06-30"}],"scenarios":[{"id":"S-01","name":"再融資利率上升+1碼","category":"融資","baseNOI":16616913,"baseDebtService":8379153,"baseCashFlow":8320721,"scenarioDebtService":9773689,"scenarioCashFlow":7631194,"cashFlowDelta":-689527,"newDSCR":"1.85x","verdict":"資產仍可維持運作；現金流受壓縮但仍高於財務契約最低要求。"},{"id":"S-02","name":"入住率下降至80%（科技業景氣衝擊）","category":"市場","baseNOI":16616913,"baseDebtService":8379153,"baseCashFlow":8320721,"scenarioNOI":13546234,"scenarioCashFlow":5115922,"cashFlowDelta":-3204799,"newDSCR":"1.62x","verdict":"現金流明顯下降；DSCR仍高於財務契約要求。可能動用準備金。"},{"id":"S-03","name":"營運費用增加+15%","category":"營運","baseNOI":16616913,"baseDebtService":8379153,"baseCashFlow":8320721,"scenarioNOI":15278592,"scenarioCashFlow":6831127,"cashFlowDelta":-1489594,"newDSCR":"1.82x","verdict":"可控。主要驅動因素：公告地價調整及保險費率上漲。"},{"id":"S-04","name":"資本支出超支+NT$120萬（屋頂）","category":"Capex","baseNOI":16616913,"baseDebtService":8379153,"baseCashFlow":8320721,"scenarioCashFlow":5527985,"cashFlowDelta":-2792736,"newDSCR":"2.03x","verdict":"一次性現金衝擊；由準備金支應。對DSCR無影響。"},{"id":"S-05","name":"估值下跌-15%","category":"估值","baseValue":282051282,"baseEquity":144688048,"baseLTV":48.7,"scenarioValue":239743590,"scenarioEquity":102380356,"scenarioLTV":57.3,"verdict":"LTV上升至57.3%——仍在財務契約範圍內。權益縮減NT$2,578萬，但資產未發生資不抵債。"}],"scenarioChart":{"labels":["2026","2027","2028","2029","2030"],"cashFlow":{"Downside":[2765347,2869307,2952475,3077228,3222772],"Base":[3597030,4033663,4366337,4719802,5094059],"Upside":[3950495,4532673,5031683,5572277,6133663]}},"mitigationPlan":[{"riskId":"R-01","action":"接觸兆豐銀行及兩家競爭金融機構，取得貸款條件書","owner":"蔡氏家族","deadline":"2026-06-30","status":"Not Started"},{"riskId":"R-02","action":"委任不動產法律顧問監控立法動態並就合規事宜提供建議","owner":"法律顧問","deadline":"2026-07-31","stat