101455,"cashFlowDelta":-604720,"newDSCR":"N/A","verdict":"持有成本增加，影響有限，年增約NT$60,000，不影響資產持有決策。"}],"scenarioChart":{"labels":["2026","2027","2028","2029","2030"],"cashFlow":{"Downside":[-720000,-744000,-768000,-792000,-816000],"Base":[-657495,-669000,-681600,-694400,-707200],"Upside":[-600000,-612000,-624000,-636000,-648000]}},"mitigationPlan":[{"riskId":"R-01","action":"每年委任正式鑑價，掌握市值動態；制定若市值回調20%以上之應對方案","owner":"蔡氏家族","deadline":"2026-06-30","status":"Not Started"},{"riskId":"R-03","action":"委任室內設計師進行全室翻新評估，確認2027年翻新預算及時程","owner":"蔡氏家族","deadline":"2026-12-31","status":"Not Started"},{"riskId":"R-04","action":"委任信託法律顧問審查蔡氏家族文件，確保資產傳承安排完善","owner":"法律顧問","deadline":"2027-01-31","status":"Not Started"}]}$j$::jsonb
