insert into public.asset_section_data (asset_id, period_id, section, data)
  select a.id, pe.id, $c$market$c$, $j${"summary":{"submarket":"土城/學府路，新北市","reportDate":"2026年5月","narrative":"新北市土城次市場受惠於住宅聚落持續人流及捷運土城線帶動的通勤租屋需求，2026年第一季住宅空置率維持在5.8%，與前季持平。要求租金年增2.5%，商業空間受學府路周邊人潮支撐，維持穩定。可比較住商混合用途資產的資本化率介於4.2%至5.8%，反映土城相對台北市區較高的收益率。住宅公寓資產地處中正路主幹道商圈，翻修後戶型租金競爭力強，一樓商業空間具備穩定客群支撐。","outlook":"偏正面","keyThemes":["捷運通勤族支撐住宅租屋需求；土城線每日旅運量逾12萬人次","學府路及老街住宅聚落維持商業空間穩定需求","租金成長溫和但穩健，年增2.5%","新供給受限；土城中正路核心地段新建住商大樓稀少","租賃住宅管理條例修訂（立法院2026年第三季審議）為主要法規風險"]},"assetCompetitiveness":{"overall":"具競爭力","strengths":["地處土城中正路核心商圈，步行可達捷運土城站","近期翻修戶型（第一期已完工；第二期進行中）","商業用途收入提供非住宅多元化，受觀光人潮支撐","低LTV（48.7%）有利再融資定價"],"weaknesses":["4戶低於市場租金3%以上 — 等待下次續租時有上調空間","1975年建物；屋頂及機電設備老化","4個平面車位對比新建產品競爭定位不足"],"opportunities":["2戶翻修後租金提升NT$9,400/戶/月","一樓商業租金低於市場約6%；2027年到期時可調整","安裝EV充電設施可吸引優質租戶並支撐溢價"],"threats":["租賃住宅管理條例修訂草案審議中","全市公告地價及房屋稅調漲成本持續上升","土城新市鎮區域2027年有新建競品預計交屋"]},"comparables":[{"address":"新北市土城區中正路88號","type":"住宅/商業混合用途","units":14,"yearBuilt":1977,"soldDate":"2025-10-15","salePrice":325885306,"pricePerUnit":9903000,"pricePM2":122000,"capRate":"4.9%","occupancy":"91%","notes":"相近年份；規模略大"},{"address":"新北市土城區英專路42號","type":"住宅","units":10,"yearBuilt":1973,"soldDate":"2025-08-22","salePrice":249826127,"pricePerUnit":10628400,"pricePM2":115700,"capRate":"5.1%","occupancy":"89%","notes":"無商業空間；NOI較低"},{"address":"新北市土城區中正路156號","type":"住宅/商業混合用途","units":12,"yearBuilt":1972,"soldDate":"2026-02-10","salePrice":284026666,"pricePerUnit":10069500,"pricePM2":114100,"capRate":"5.3%","occupancy":"93%","notes":"最具可比性；年份及格局相近"},{"address":"新北市土城區民族路18號","type":"住宅","units":8,"yearBuilt":1976,"soldDate":"2025-12-05","salePrice":196099547,"pricePerUnit":10428375,"pricePM2":110600,"notes":"規模較小；入住率較低；裝潢水準較低","capRate":"5.6%","occupancy":"87%"}],"rentComparables":[{"address":"中正路88號","unitType":"1房","areaM2":63,"askingRent":97313,"rentPM2":657,"occupancy":"93%","amenities":"翻修"},{"address":"英專路42號","unitType":"1房","areaM2":60,"askingRent":90966,"rentPM2":645,"occupancy":"90%","amenities":"標準"},{"address":"中正路156號","unitType":"1房","areaM2":65,"askingRent":95197,"rentPM2":623,"occupancy":"92%","amenities":"翻新"},{"address":"住宅公寓（本案）","unitType":"1房 穩定戶","areaM2":67,"askingRent":92612,"rentPM2":588,"occupancy":"94%","amenities":"翻修"},{"address":"中正路88號","unitType":"2房","areaM2":87,"askingRent":136802,"rentPM2":669,"occupancy":"91%","amenities":"翻修"},{"address":"中正路156號","unitType":"2房","areaM2":89,"askingRent":131161,"rentPM2":627,"occupancy":"90%","amenities":"翻新"},{"address":"住宅公寓（本案）","unitType":"2房 穩定戶","areaM2":91,"askingRent":127165,"rentPM2":595,"occupancy":"89%","amenities":"翻修"}],"capRateTrend":{"labels":["Q1'23","Q2'23","Q3'23","Q4'23","Q1'24","Q2'24","Q3'24","Q4'24","Q1'25","Q2'25","Q3'25","Q4'25","Q1'26"],"values":[5.8,5.75,5.7,5.65,5.55,5.48,5.42,5.38,5.32,5.28,5.22,5.18,5.15]},"vacancyTrend":{"labels":["Q1'23","Q2'23","Q3'23","Q4'23","Q1'24","Q2'24","Q3'24","Q4'24","Q1'25","Q2'25","Q3'25","Q4'25","Q1'26"],"submarket":[6.2,6,5.8,5.6,5.4,5.2,5.4,5.6,5.7,5.8,5.9,5.8,5.8],"asset":[8.3,8.3,8.3,8.3,8.3,8.3,6.7,6.7,6.7,8.3,8.3,8.3,16.7]},"marketRisks":[{"title":"租賃住宅管理條例修訂","level":"High","description":"立法院預計2026年第三季審議。若通過，每年租金調漲上限為3%，低於目前市場成長率，將抑制NOI增長。"},{"title":"土城觀光景氣波動","level":"Medium","description":"一樓商業租金依賴土城觀光客流量。若主要景點翻修或交通調整造成旅客下降，商業租金可能承壓。"},{"title":"建築材料及工資通膨","level":"Medium","description":"勞工成本及建材費用持續上漲，提高資本支出需求並降低翻修投資報酬。"},{"title":"保險市場趨緊","level":"Low","description":"台灣商業不動產保險費率持續每年上漲6–10%，影響全市場。"}],"marketOpportunities":[{"title":"4戶低於市場租金之調整空間","description":"四戶租金低於市場行情3–6%。下次續租時調整租金，每年可增加NT$29萬至NT$46萬NOI。"},{"title":"2027年商業空間租金調升","description":"一樓商業租約2027年1月到期。目前租金低於市場約6%。以市場租金續約每年可增加約NT$134,000。"},{"title":"供給受限支撐資產價值","description":"中正路核心地段新建案稀少，同類型產品競爭有限，支撐估值及租金水準。"},{"title":"EV充電設施溢價潛力","description":"租戶對EV充電設施需求持續增加。安裝2組Level 2充電樁可支撐每個車位每月NT$4,500以上的溢價。"}],"marketImplication":{"title":"市場動態對住宅公寓資產的意涵","body":"土城次市場基本面支持目前持有並改善的策略。捷運支撐的穩定通勤需求及住宅聚落帶動的商業人流，為資產價值提供有力支撐。主要風險——租賃管理條例修法——應密切追蹤，並在2026年第四季再融資財務模型中以悲觀情境反映。最具行動力的上行空間，在於下次續租時將4戶低市場租金進行正常化，此舉無需資本投入，即可每年增加NT$29萬至NT$46萬NOI。第二期翻修完工後，本資產競爭定位將顯著提升。"}}$j$::jsonb
  from public.assets a join public.periods pe on pe.client_id = a.client_id and pe.period = '2026-Q2'
  where a.code = $c$tsai-005$c$ and a.client_id = (select id from public.clients where slug = 'tsai-family')
  on conflict (asset_id, period_id, section) do update set data = excluded.data, updated_at = now();

